mapper.select:
select cmp_check_inventory.* from cmp_check_inventory join cmp_check_inventory_b on cmp_check_inventory.id = cmp_check_inventory_b.mainid where 1=1
and cmp_check_inventory_b.check_bill_no = #{checkBillNo}
and cmp_check_inventory_b.checkid like concat('%', #{checkId}, '%') order by cmp_check_inventory_b.pubts desc limit 1
